const express = require('express');
const bodyParser = require('body-parser');
const twilio = require('twilio');
const redis = require('redis');
const crypto = require('crypto');

const app = express();
app.use(bodyParser.json());

const accountSid = 'your_twilio_account_sid';
const authToken = 'your_twilio_auth_token';
const client = new twilio(accountSid, authToken);

const redisClient = redis.createClient();

app.post('/send-code', async (req, res) => {
  const { phoneNumber } = req.body;
  if (!phoneNumber) return res.status(400).json({ error: 'Phone number is required' });

  const code = Math.floor(100000 + Math.random() * 900000);
  await redisClient.set(phoneNumber, code, 'EX', 600);

  try {
    await client.messages.create({
      body: `Your verification code is ${code}`,
      from: '+your_twilio_phone_number',
      to: phoneNumber
    });
    res.status(200).json({ message: 'Code sent successfully' });
  } catch (error) {
    res.status(500).json({ error: 'Failed to send code' });
  }
});

app.post('/verify-code', async (req, res) => {
  const { phoneNumber, code } = req.body;
  if (!phoneNumber || !code) return res.status(400).json({ error: 'Phone number and code are required' });

  try {
    const storedCode = await redisClient.get(phoneNumber);
    if (!storedCode) return res.status(401).json({ error: 'Invalid or expired code' });

    if (code === storedCode) {
      await redisClient.del(phoneNumber); // Clear the code after successful verification
      res.status(200).json({ message: 'Access granted' });
    } else {
      res.status(401).json({ error: 'Invalid code' });
    }
  } catch (error) {
    res.status(500).json({ error: 'Failed to verify code' });
  }
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});